def n_hostile_pairs(L: list) -> int:
    hostile_pairs = 0
    n = len(L)
    for i in range(n):
        for j in range(i + 1, n):
            if not set(str(L[i])) & set(str(L[j])):
                hostile_pairs += 1
    return hostile_pairs
